	router.GET(baseURL+"/api/movies", wrapper.GetAllMovies)
	router.POST(baseURL+"/api/movies", wrapper.CreateMovie)
	router.GET(baseURL+"/api/movies/health", wrapper.GetMoviesServiceHealth)
	router.GET(baseURL+"/api/payments", wrapper.GetAllPayments)
