	router.GET(baseURL+"/api/subscriptions", wrapper.GetAllSubscriptions)
	router.POST(baseURL+"/api/subscriptions", wrapper.CreateSubscription)
	router.GET(baseURL+"/api/users", wrapper.GetAllUsers)
